#include <bits/stdc++.h>
using namespace std;

int N, L;
int c[505], l[505];
int f[4005];
const int INF = 1e8;

int main() {
    cin >> N >> L;
    for (int i = 1; i <= N; i++) {
        cin >> c[i] >> l[i];
        l[i] = min(l[i], L);
    }
    for (int i = 1; i <= 2 * L; i++) {
        f[i] = INF;
    }
    for (int i = 1; i <= N; i++) {
        for (int j = 2 * L; j >= l[i]; j--) {
            f[j] = min(f[j], f[j - l[i]] + c[i]);
        }
    }
    int ans = INF;
    for (int i = L; i <= 2 * L; i++) {
        ans = min(ans, f[i]);
    }
    if (ans == INF) {
        cout << "no solution";
    }
    else {
        cout << ans;
    }
    return 0;
}
